private void SmoothMoveList(Point start, Point end, double timeToMove)
{
    int steps = Math.Max(Math.Abs(end.X - start.X), Math.Abs(end.Y - start.Y));
    int delayBetweenSteps = CalculateDelayBetweenSteps(timeToMove, steps);

    for (int i = 0; i <= steps; i++)
    {
        int newX = start.X + (end.X - start.X) * i / steps;
        int newY = start.Y + (end.Y - start.Y) * i / steps;
        SetCursorPos(newX, newY);
        Thread.Sleep(delayBetweenSteps);
    }
}

private int CalculateDelayBetweenSteps(double timeToMove, int steps)
{
    return (int)((timeToMove / steps) * 1000);
}
